-- 1. Usunięcie starej tabeli i powiązanych wpisów
drop table if exists public.joined_events cascade;
drop table if exists public.events cascade;

-- 2. Tworzenie tabeli
create table public.events (
  id uuid primary key default gen_random_uuid(),
  title text not null,
  description text not null,
  type text not null check (type in ('landmark', 'event')),
  gmina text not null,
  latitude double precision not null,
  longitude double precision not null,
  category text not null check (category in ('Kultura', 'Ekologia', 'Edukacja', 'Rozrywka', 'Sport')),
  event_date text not null,
  event_day text not null,
  event_time text not null,
  location_name text not null,
  attendees_count integer not null default 0
);

alter table public.events enable row level security;

create policy "Każdy może przeglądać mapę i wydarzenia" on public.events
  for select using (true);

create policy "Zalogowani mogą aktualizować licznik uczestników" on public.events
  for update using (auth.uid() is not null);

create table public.joined_events (
  id uuid default gen_random_uuid() primary key,
  user_id uuid references public.profiles(id) on delete cascade not null,
  event_id uuid references public.events(id) on delete cascade not null,
  title text not null,
  date timestamp with time zone not null default now(),
  location text not null,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null,
  unique (user_id, event_id)
);

alter table public.joined_events enable row level security;

create policy "Każdy widzi zapisy na wydarzenia" on public.joined_events
  for select using (true);

create policy "Użytkownicy mogą zapisywać się na wydarzenia" on public.joined_events
  for insert with check (auth.uid() = user_id);

create policy "Użytkownicy mogą wypisać się z wydarzenia" on public.joined_events
  for delete using (auth.uid() = user_id);

-- 3. Zasilenie bazy danych 105 unikalnymi wpisami
